#include "controller.h"

static bool controller_temperature_is_rising(const controller_t *controller, int temperature_c, bool had_previous_temperature_sample)
{
    return controller != 0 && had_previous_temperature_sample && temperature_c > controller->previous_temperature_c;
}

static bool controller_is_timed_out(uint32_t now_ms, uint32_t last_ms)
{
    return (now_ms - last_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static void controller_apply_output(controller_t *controller, bool inlet_open, bool heater_on, controller_state_t state)
{
    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;
    controller->state = state;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;
    bool timeout_fault = false;
    bool inlet_open = false;
    bool heater_on = false;
    controller_state_t state = CONTROLLER_STATE_SAFE_IDLE;
    bool had_previous_temperature_sample = controller->has_valid_temperature;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (controller->has_valid_temperature) {
            controller->previous_temperature_c = controller->last_temperature_c;
        }
        controller->has_valid_temperature = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        timeout_fault = true;
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_temperature = false;
        timeout_fault = true;
        break;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_level = false;
        timeout_fault = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (timeout_fault) {
        controller_set_safe_idle(controller);
    } else if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
    } else if (
        controller_is_timed_out(input.now_ms, controller->last_temperature_ms) ||
        controller_is_timed_out(input.now_ms, controller->last_level_ms)
    ) {
        timeout_fault = true;
        controller_set_safe_idle(controller);
    } else {
        const int temperature_c = controller->last_temperature_c;
        const int level = controller->last_level;

        if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
            inlet_open = true;
            heater_on = false;
            state = CONTROLLER_STATE_FILLING;
        } else {
            inlet_open = false;

            if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
                heater_on = (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) ? true : controller->heater_on;
                if (temperature_c >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    heater_on = false;
                }
            }

            if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                heater_on = true;
                state = CONTROLLER_STATE_HEATING;
            } else if (temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                state = CONTROLLER_STATE_HOLDING;
            } else if (temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                if (controller_temperature_is_rising(controller, temperature_c, had_previous_temperature_sample)) {
                    heater_on = false;
                } else {
                    heater_on = controller->heater_on;
                }
                state = CONTROLLER_STATE_HOLDING;
            } else {
                heater_on = false;
                state = CONTROLLER_STATE_HOLDING;
            }

            if (level < CONTROLLER_MIN_HEATING_LEVEL) {
                heater_on = false;
                if (state != CONTROLLER_STATE_FILLING) {
                    state = CONTROLLER_STATE_FILLING;
                }
            }
        }

        controller_apply_output(controller, inlet_open, heater_on, state);
